return new Promise(function (resolve, reject) {
  const username = "{{woo_user}}"; 
  const password = "{{woo_pass}}"; 
  const url = "{{startUrl}}wp-json/wc/v3/orders/?customer_id={{userId}}";
  const data = '{"currency":"USD","billing":{"first_name":"{{firstName}}","last_name":"{{lastName}}","company":"{{company}}","address_1":"{{street}}","address_2":"{{address2}}","city":"{{city}}","state":"FL","postcode":"{{zipCode}}","country":"US","email":"{{email}}","phone":"{{phone}}"},"line_items":[{"product_id":1593,"quantity":1}]}';
  let headers = new Headers();
  headers.set('Content-Type', 'application/json');
  headers.set('Authorization', 'Basic ' + btoa(username + ":" + password));
  fetch(url, {method:'POST',
      body: data,
      headers: headers,
      credentials: 'omit'
      })
  .then(function(response) {
    if (response.ok) {
    resolve(response.json())
    } else {
    reject(new Error('error'))
    } 
  })
})
